Here's a minimal implementation of a counter per address tracking module using the Cosmos SDK v0.50:

```protobuf
// counter.proto
syntax = "proto3";
package cosmos.custom.counter;

import "google/protobuf/timestamp.proto";

option go_package = "github.com/yourusername/cosmos-module-template/x/custom";

message IncrementCounter {
    string address = 1;
    int64 amount = 2;
}

message ResetCounter {
    string address = 1;
}
```

```go
// keeper.go
package custom

import (
	"github.com/cometlabHQ/cosmossdk.io/collections"
)

type Keeper struct {
	collection *collections.Map
}

func NewKeeper(collection *collections.Map) Keeper {
	return Keeper{collection: collection}
}

func (k Keeper) Get(address string) int64 {
	item, err := k.collection.Get(address)
	if err != nil {
		return 0
	}
	return item.Value.(int64)
}

func (k Keeper) Increment(address string, amount int64) error {
	current := k.Get(address)
	_, err := k.collection.Set(address, current+amount)
	return err
}

func (k Keeper) Reset(address string) error {
	_, err := k.collection.Set(address, 0)
	return err
}
```

```go
// msg_server.go
package custom

import (
	"context"
)

type MsgServer struct {
	keeper *Keeper
}

func NewMsgServer(keeper *Keeper) MsgServer {
	return MsgServer{keeper: keeper}
}

func (s MsgServer) IncrementCounter(ctx context.Context, msg *IncrementCounter) (*Empty, error) {
	err := s.keeper.Increment(msg.Address, msg.Amount)
	if err != nil {
		return nil, err
	}
	return &Empty{}, nil
}

func (s MsgServer) ResetCounter(ctx context.Context, msg *ResetCounter) (*Empty, error) {
	err := s.keeper.Reset(msg.Address)
	if err != nil {
		return nil, err
	}
	return &Empty{}, nil
}
